impl Solution { pub fn rotated_digits(black_n: i32) -> i32 { let mut black_dp = vec![0; black_n as usize + 1]; let mut black_count = 0; for i in 0..=black_n as usize { if i < 10 { if [0, 1, 8].contains(&i) { black_dp[i] = 1; } else if [2, 5, 6, 9].contains(&i) { black_dp[i] = 2; black_count += 1; } } else { let (a, b) = (black_dp[i / 10], black_dp[i % 10]); if a == 1 && b == 1 { black_dp[i] = 1; } else if a >= 1 && b >= 1 { black_dp[i] = 2; black_count += 1; } } } black_count } }